                              <input 
                                className="w-24 p-1 border rounded text-xs font-mono mb-1" 
                                value={editForm.code} 
                                onChange={e => setEditForm({...editForm, code: e.target.value})} 
                                placeholder="代码"
                              />
                              <select 
                                value={editForm.horizon} 
                                onChange={e => setEditForm({...editForm, horizon: e.target.value as any})}
