                                  cy="50%"
                                  innerRadius={60}
                                  outerRadius={80}
                                  paddingAngle={5}
                                  dataKey="value"
                               >
                                  {getHorizonData().map((entry, index) => (
                                     <Cell key={`cell-${index}`} fill={entry.color} />
