           csv += `${plan.target_date},"${item.symbol}","${item.action}","${item.price_target}","${item.reason.replace(/"/g, '""')}","${item.status}"\n`;
        });
     });
     downloadFile(csv, `TradingPlans_${new Date().toISOString().split('T')[0]}.csv`, 'text/csv');
