): Promise<AnalysisResult> => {
  const prompt = `分析 ${market} 市场 ${mode === 'chain' ? '产业链' : '资金配置'}。输入: ${inputData}`;

  if (provider === ModelProvider.GEMINI_INTL) {
    const apiKey = settings?.geminiKey || process.env.API_KEY;
