    try {
      const response = await runGeminiSafe(ai, GEMINI_MODEL_COMPLEX, {
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: opportunitySchema
        }
