                        />
                        <input 
                          disabled={isHistoryView}
                          value={h.code} 
                          onChange={(e) => updateHolding(i, 'code', e.target.value)}
                          className="text-[10px] text-slate-400 font-mono bg-transparent border-none focus:ring-0 w-full p-0"
